import{_ as t,o,c as d,a4 as a}from"./chunks/framework.LQ2Ga-wM.js";const p=JSON.parse('{"title":"Armes","description":"","frontmatter":{},"headers":[],"relativePath":"framework/modules/weapons.md","filePath":"framework/modules/weapons.md","lastUpdated":1781601194000}'),n={name:"framework/modules/weapons.md"};function r(i,e,c,s,l,m){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="armes" tabindex="-1">Armes <a class="header-anchor" href="#armes" aria-label="Permalink to &quot;Armes&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Domaine intégré à l&#39;inventaire</p><p>La gestion des armes fait partie du domaine plat <strong><code>inventory</code></strong> (<code>inventory/client/weapons.lua</code>, <code>inventory/server/weapons.lua</code>), chargé via le <code>fxmanifest.lua</code>. Il n&#39;y a pas de registre de modules ni de domaine <code>weapons</code> séparé. La logique vit sous <code>Inventory</code> (notamment <code>Inventory.Weapon</code> et <code>Inventory.Akimbo</code>) et les données statiques sous <code>InventoryData</code>.</p></div><p>Une arme est un item d&#39;inventaire : elle occupe un slot, porte ses caractéristiques dans sa <strong>métadonnée</strong> (munitions, durabilité, composants, numéro de série) et s&#39;équipe depuis la barre rapide. Cette page décrit le cycle équipement/munitions, l&#39;akimbo, les composants et les points d&#39;entrée serveur réels.</p><h2 id="donnees-statiques" tabindex="-1">Données statiques <a class="header-anchor" href="#donnees-statiques" aria-label="Permalink to &quot;Données statiques&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Table</th><th>Fichier</th><th>Contenu</th></tr></thead><tbody><tr><td><code>InventoryData.Weapons</code></td><td><code>inventory/shared/data/weapons.lua</code></td><td>Définitions des armes (<code>label</code>, <code>weight</code>, <code>model</code>/<code>hash</code>, <code>durability</code>, <code>attachPoint</code>, <code>allowedAmmos</code>, <code>throwable</code>...)</td></tr><tr><td><code>InventoryData.Components</code></td><td><code>inventory/shared/data/components.lua</code></td><td>Composants par type (<code>Shared[type]</code>) et par arme précise (<code>Specific[weaponName]</code>)</td></tr><tr><td><code>InventoryData.WeaponMaps</code></td><td><code>Config.Inventory.WeaponMaps</code></td><td>Tables de correspondance (<code>TypeMap</code>, <code>Functional</code>, <code>Bows</code>, <code>Lanterns</code>, <code>ThrownAmmo</code>...)</td></tr><tr><td><code>InventoryData.AmmoShared</code></td><td><code>Config.Inventory.Ammo</code></td><td>Munitions : <code>TypeHash</code>, <code>MaxAmmo</code>, <code>Labels</code>, <code>Types</code> (groupes acceptés)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Définir une arme</p><p>Comme tout item, une arme est single-source en DB (<code>Items</code>). Les définitions statiques de <code>InventoryData.Weapons</code> servent de base ; voir <a href="./inventory#armes-et-metadonnees">Définition d&#39;un item</a> dans le module Inventaire pour les champs reconnus (<code>weapon</code>, <code>durability</code>, <code>attachPoint</code>, <code>allowedAmmos</code>, <code>throwable</code>).</p></div><h2 id="metadonnees-d-arme" tabindex="-1">Métadonnées d&#39;arme <a class="header-anchor" href="#metadonnees-d-arme" aria-label="Permalink to &quot;Métadonnées d&#39;arme&quot;">​</a></h2><p>À la création, une arme reçoit dans sa métadonnée :</p><table tabindex="0"><thead><tr><th>Clé</th><th>Description</th></tr></thead><tbody><tr><td><code>durability</code></td><td>Pourcentage de durabilité (défaut <code>100</code>).</td></tr><tr><td><code>ammo</code></td><td>Munitions chargées.</td></tr><tr><td><code>ammoType</code></td><td>Type de munition actuellement chargé.</td></tr><tr><td><code>components</code></td><td>Liste des composants montés.</td></tr><tr><td><code>serial</code></td><td>Numéro de série généré, ou <code>false</code> si <code>registered == false</code>.</td></tr><tr><td><code>used</code></td><td>Drapeau de ré-équipement au respawn / reconnexion.</td></tr></tbody></table><h2 id="equipement-client" tabindex="-1">Équipement (client) <a class="header-anchor" href="#equipement-client" aria-label="Permalink to &quot;Équipement (client)&quot;">​</a></h2><p>L&#39;équipement est piloté depuis la barre rapide. Le client suit l&#39;arme tenue en main via un planificateur (<code>Scheduler:Register(&#39;inventory:heldWeapon&#39;, ...)</code>) et applique automatiquement les munitions et composants.</p><table tabindex="0"><thead><tr><th>Fonction (<code>Inventory.Weapon</code>)</th><th>Rôle</th></tr></thead><tbody><tr><td><code>Weapon.Equip(slotItem)</code></td><td>Équipe l&#39;arme du slot : résout le hash, charge les munitions, applique les composants, publie l&#39;état</td></tr><tr><td><code>Weapon.Disarm(weapon)</code></td><td>Range l&#39;arme et nettoie l&#39;état répliqué</td></tr><tr><td><code>Weapon.Give(p, hash, ammo, equipNow)</code></td><td>Donne l&#39;arme au ped et attend qu&#39;elle soit présente</td></tr><tr><td><code>Weapon.LoadAmmo(p, hash, ammoTypeName, amount)</code></td><td>Charge un type/quantité de munitions sur l&#39;arme</td></tr><tr><td><code>Weapon.ApplyComponents(p, hash, weaponName, md)</code></td><td>Applique les composants décrits dans la métadonnée</td></tr></tbody></table><p>Quand le joueur appuie sur la touche d&#39;usage d&#39;un slot d&#39;arme de la barre rapide, le client reçoit <code>lo:inventory:useWeapon</code> : il dégaine, range, ou bascule l&#39;akimbo selon l&#39;état courant.</p><h3 id="recharge" tabindex="-1">Recharge <a class="header-anchor" href="#recharge" aria-label="Permalink to &quot;Recharge&quot;">​</a></h3><p>La touche <code>R</code> (<code>Keys:RegisterKey(&#39;reload_weapon&#39;, ...)</code>) cherche le meilleur slot de munitions compatible et recharge l&#39;arme tenue. La recharge est aussi déclenchable depuis l&#39;interface via les callbacks NUI <code>reloadAmmo</code> / <code>removeAmmo</code>.</p><h2 id="munitions" tabindex="-1">Munitions <a class="header-anchor" href="#munitions" aria-label="Permalink to &quot;Munitions&quot;">​</a></h2><p>Les munitions sont elles-mêmes des items (avec un champ <code>ammoType</code>). Charger des munitions retire l&#39;item correspondant de l&#39;inventaire et écrit le compte dans la métadonnée de l&#39;arme.</p><table tabindex="0"><thead><tr><th>Point d&#39;entrée serveur</th><th>Type</th><th>Rôle</th></tr></thead><tbody><tr><td><code>lo:inventory:updateWeapon</code></td><td>callback / event sécurisé</td><td>Met à jour la métadonnée (<code>load</code>, <code>ammo</code>, <code>throw</code>) après tir/recharge/lancer</td></tr><tr><td><code>lo:inventory:loadInventoryAmmo</code></td><td>event sécurisé</td><td>Charge des munitions depuis l&#39;inventaire (respecte <code>allowedAmmos</code> et la taille de chargeur)</td></tr><tr><td><code>lo:inventory:removeAmmoFromWeapon</code></td><td>callback</td><td>Décharge l&#39;arme et rend les munitions à l&#39;inventaire</td></tr><tr><td><code>lo:inventory:mirrorAmmo</code></td><td>event sécurisé</td><td>Synchronise le compte de munitions entre deux armes akimbo</td></tr></tbody></table><p>Tous les events réseau entrants sont protégés par <code>Net:SecureEvent</code> (limitation de débit), et le serveur revalide chaque opération (l&#39;arme existe, l&#39;item munition est compatible, etc.).</p><h2 id="akimbo" tabindex="-1">Akimbo <a class="header-anchor" href="#akimbo" aria-label="Permalink to &quot;Akimbo&quot;">​</a></h2><p>Les armes une main pouvant être maniées en paire sont gérées par <code>Inventory.Akimbo</code> (équipement gauche/droite, partage des munitions, ré-équipement). Principales fonctions :</p><table tabindex="0"><thead><tr><th>Fonction (<code>Inventory.Akimbo</code>)</th><th>Rôle</th></tr></thead><tbody><tr><td><code>Akimbo.IsAkimboGun(hash)</code></td><td>Vrai si l&#39;arme peut être maniée en paire</td></tr><tr><td><code>Akimbo.Equip(name, id)</code> / <code>Akimbo.Remove(name, id)</code></td><td>Équipe / retire une arme akimbo</td></tr><tr><td><code>Akimbo.GetAkimboPartner(slot, hash)</code></td><td>Renvoie le slot de l&#39;arme jumelle</td></tr><tr><td><code>Akimbo.IsEquipped(id)</code> / <code>Akimbo.GetEquippedCount()</code></td><td>État de la paire</td></tr><tr><td><code>Akimbo.Reset()</code></td><td>Réinitialise le suivi (déconnexion / changement de perso)</td></tr></tbody></table><p>Le serveur enregistre l&#39;état d&#39;usage de chaque slot via <code>lo:inventory:setWeaponUsed</code> et le slot actif via <code>lo:inventory:setCurrentWeaponSlot</code>.</p><h2 id="composants" tabindex="-1">Composants <a class="header-anchor" href="#composants" aria-label="Permalink to &quot;Composants&quot;">​</a></h2><p>Un composant est un item dont la définition expose <code>component = true</code>, un <code>type</code> (catégorie d&#39;emplacement, ex. matériau, teinte) et une liste <code>compatibleWeapons</code>. Le montage retire le composant de l&#39;inventaire, remplace tout composant existant du même <code>type</code> (rendu à l&#39;inventaire) et l&#39;ajoute à <code>metadata.components</code> de l&#39;arme.</p><table tabindex="0"><thead><tr><th>Callback serveur</th><th>Données</th><th>Rôle</th></tr></thead><tbody><tr><td><code>lo:inventory:attachComponent</code></td><td><code>{ componentSlot, weaponSlot }</code></td><td>Monte un composant sur l&#39;arme</td></tr><tr><td><code>lo:inventory:detachComponent</code></td><td><code>{ weaponSlot, componentName }</code></td><td>Démonte un composant et le rend à l&#39;inventaire</td></tr></tbody></table><p>Côté client (<code>inventory/client/weapons.lua</code>), les callbacks NUI <code>attachComponent</code> / <code>detachComponent</code> relaient ces actions, et l&#39;application visuelle des composants suit un ordre de priorité (fonctionnel, matériau, gravure, matériau de gravure, teinte) via <code>InventoryData.Components</code>.</p><h2 id="durabilite" tabindex="-1">Durabilité <a class="header-anchor" href="#durabilite" aria-label="Permalink to &quot;Durabilité&quot;">​</a></h2><p>La durabilité d&#39;une arme (pourcentage dans <code>metadata.durability</code>) décroît à l&#39;usage. Une arme à <code>0</code> est inutilisable (la recharge est refusée avec une notification). La logique de durabilité générique des items est décrite dans <a href="./inventory#armes-et-metadonnees">Définition d&#39;un item</a> du module Inventaire.</p>',29)])])}const h=t(n,[["render",r]]);export{p as __pageData,h as default};
